34	    expect(result).toEqual({ results: [{ premium: 93 }] });
35	  });
36	  it("single plain potion (newcomer first item) → base 40 + first 4 + fee 5 = 49 G", () => {
37	    const result = runScenario({
38	      customer: { yearsWithMHPCO: 0 },
39	      steps: [{ op: "quote", items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }] }],
40	    });
41	    expect(result).toEqual({ results: [{ premium: 49 }] });
42	  });
43	
44	  // --- Components and "building blocks of 3 alike" ---
45	  it("2 runes → base 50 G (no block); final premium with first-insurance+fee = 60 G", () => {
46	    const result = runScenario({
47	      customer: { yearsWithMHPCO: 0 },
48	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
49	    });
50	    expect(result).toEqual({ results: [{ premium: 60 }] });
