52	  it.todo("3 runes → base 60 G (block applies)");
53	  it.todo("4 runes → base 100 G (no block — block requires exactly 3)");
54	  it.todo("7 runes → base 175 G (one block of 3 + 4 singles = 60 + 100)");
55	  it.todo("2 runes + 1 moonstone → base 75 G (no block: different types)");
56	  it.todo("3 runes + 3 moonstones → base 120 G (two separate blocks)");
57	
58	  // --- Item-specific modifiers (cursed, high enchantment) ---
59	  it.todo("cursed sword adds 50% surcharge on the cursed item's base premium");
60	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
61	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
62	  it.todo("cursed sword with enchantment 5 → both curse and high-enchantment surcharges apply");
63	
64	  // --- Policy-wide modifiers ---
65	  it.todo("loyalty discount applies for customer with exactly 2 years");
66	  it.todo("loyalty discount does NOT apply for customer with 1 year");
67	  it.todo("first insurance surcharge applies per item in a quote");
68	  it.todo("follow-up contract discount (15%) applies to second quote in scenario");
69	
70	  // --- Modifier scope on multi-item policies ---
71	  it.todo("cursed sword + plain amulet → cursed surcharge applies only to cursed item (210 G before further modifiers and fee)");
72	
73	  // --- Rounding ---
74	  it.todo("premium of 197.5 G rounds UP to 198 G (MHPCO's favor)");
75	
76	  // --- Integration examples ---
77	  it.todo("newcomer with cursed sword (steel, ench 3) → premium 165 G");
78	  it.todo("long-standing customer (3yrs), 2nd quote, cursed sword (steel, ench 7) → premium 160 G; first-insurance still applies to each new sword");
79	
80	  // --- Quote error cases ---
81	  it.todo("quote with unknown item type → CLI exits non-zero, writes to stderr, no results to stdout");
82	
83	  // --- Claim: standard reimbursement ---
84	  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (full minus 100 deductible)");
85	  it.todo("damage to a rune (insurance 250 G), damage 200 G → payout 100 G");
86	
87	  // --- Claim: enchantment threshold ---
88	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
89	
90	  // --- Claim: dragon material ---
91	  it.todo("dragon sword, enchantment 5, damage 800 G → payout 700 G (full minus deductible)");
92	
93	  // --- Claim: enchantment threshold vs dragon material ---
94	  it.todo("dragon sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins)");
95	  it.todo("dragon sword, enchantment exactly 8, damage 1000 G → payout 400 G (high-ench clause applies, then deductible)");
96	
97	  // --- Claim: deductible per damage event ---
98	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible once per damaged item)");
99	
100	  // --- Claim: multiple items of same type ---
101	  it.todo("two swords insured; dragon attack damages both → each damage entry treated separately with own deductible");
102	  it.todo("claim has more entries of a type than policy covers → CLI exits non-zero (claim rejected)");
103	
104	  // --- Claim: cap exhaustion ---
105	  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
106	  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value; modifiers don't raise cap)");
107	  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block discount affects premium only)");
108	  it.todo("sword insured; two successive claims of 1500 G → first 1400 G payout cap remaining 600; second 600 G payout cap remaining 0");
109	
110	  // --- Claim: rounding ---
111	  it.todo("payout calculation 350.5 G rounds DOWN to 350 G");
112	
113	  // --- Claim error cases ---
114	  it.todo("claim references item not in policy → CLI exits non-zero, stderr");
115	  it.todo("claim references item with unknown type → CLI exits non-zero, stderr");
116	  it.todo("claim has damage with amount: -200 → CLI exits non-zero, stderr");
117	});
