1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	type Item = { type: string };
13	type Step = { op: "quote"; items: Item[] };
14	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
15	type QuoteResult = { premium: number };
16	
17	const itemPremium = (item: Item): number => {
18	  const base = BASE_PREMIUM[item.type];
19	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE_RATE;
20	  return base + firstInsuranceSurcharge;
21	};
22	
23	const quoteStep = (step: Step): QuoteResult => {
24	  const itemsTotal = step.items.reduce((acc, item) => acc + itemPremium(item), 0);
25	  return { premium: itemsTotal + PROCESSING_FEE };
26	};
27	
28	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => ({
29	  results: scenario.steps.map(quoteStep),
30	});
